options.afterRender:
let { controlMode, emergency, lockout, state } = context.data;

const statusEle = $('#plant-status');
const infoEle = $('#plant-info');

if (lockout) {
  statusEle.text('LOCKOUT');
  infoEle.text('Chiller control stopped - Manual Reset Required')
  statusEle.removeClass('emergency')
  statusEle.addClass('lockout')
} else if (emergency) {
  statusEle.text('EMERGENCY');
  infoEle.text('Chiller control stopped');
  statusEle.addClass('emergency')
  statusEle.removeClass('lockout')
} else {
  statusEle.text(controlMode + ' - ' + state);
  infoEle.text('')
  statusEle.removeClass('emergency')
  statusEle.removeClass('lockout')
}

options.styles:
#plant-status {
  font-weight: bold;
  color: green;
}

.lockout {
  color: red !important;
}

.emergency {
  color: orangered !important;
}

#plant-info {
  font-style: italic;
  font-weight: 300;
}

options.afterRender:
const equipmentId = context.data?.towerId;
const panel = $(`.cooling-tower-control[data-equipment-id="${equipmentId}"]`);
const mode = panel.find('.cooling-tower-mode');
const modeUpdateButton = panel.find('.cooling-tower-change-mode');
const modeBadges = panel.find('.mode-badges');
const deviceModeBadges = panel.find('.device-mode-badges');
const availBadges = panel.find('.avail-badges');
const availability = panel.find('.cooling-tower-availability');
const status = panel.find('.cooling-tower-status');
const stateText = panel.find('.state-text');
const manualDevicesPanel = panel.find('.tower-manual-devices');
const buttons = panel.find('button');
const startButton = panel.find('.tower-start');
const stopButton = panel.find('.tower-stop');
const startButtonWrapper = panel.find('.tower-start-wrapper');
const stopButtonWrapper = panel.find('.tower-stop-wrapper');
const startStopButtons = panel.find('.tower-start, .tower-stop');
let currentMode = context.data?.remoteMode === 'AUTO' ? 'AUTO' : 'MANUAL';
let currentState = context.data?.state || 'UNKNOWN';
let currentAvail = context.data?.availability || 'AVAILABLE';

const equipmentName = (fallback, device) => device?.deviceId || device?.id || fallback;
const modeIssue = (device) => {
  const issues = [];
  if (device?.autoMode && device.autoMode !== 'AUTO') issues.push('Manual');
  if (device?.remoteMode && device.remoteMode !== 'AUTO') issues.push('Remote');
  return issues;
};
const collectManualDevices = () => {
  const manualDevices = [];
  const addDevice = (label, device) => {
    const issues = modeIssue(device);
    if (issues.length > 0) manualDevices.push((label + ' ' + equipmentName('', device) + ' (' + issues.join(', ') + ')').trim());
  };

  (context.data?.fans || []).forEach((fan, index) => addDevice('Fan ' + (index + 1), fan));
  (context.data?.valves || []).forEach((valve, index) => addDevice('Valve ' + (index + 1), valve));
  return manualDevices;
};
let manualDevices = collectManualDevices();

const renderManualDevices = () => {
  if (manualDevices.length === 0) {
    manualDevicesPanel.empty();
    return;
  }

  manualDevicesPanel.html('<span class="tower-manual-devices-title">Manual/remote devices:</span> ' + manualDevices.join(', '));
};
const applyModeUpdateState = () => {
  modeUpdateButton.prop('disabled', mode.val() === '');
};
const setLocalMode = (mode) => {
  currentMode = mode;
  applyModeBadges();
}

const applyModeBadges = () => {
  let result = '';

  if (currentMode !== 'AUTO') {
    result = `<span style="margin-left: 10px;" class="badge rounded-pill bg-orange"><i class="fa fa-user" aria-hidden="true"></i> Remote</span>`
  } else {
    result = `<span style="margin-left: 10px;" class="badge rounded-pill bg-success"><i class="fa fa-leaf" aria-hidden="true"></i> Auto</span>`
  }

  modeBadges.html(result);
}

const applyDeviceModeBadges = () => {
  let result = '';

  if (manualDevices.length > 0) {
    result = `<span style="margin-left: 10px;" class="badge rounded-pill bg-warning" title="At least one device is in MANUAL or REMOTE mode"><i class="fa fa-child" aria-hidden="true"></i> Device</span>`
  }
  deviceModeBadges.html(result);
}

const setLocalAvail = (avail) => {
  currentAvail = avail;
  applyAvailBadges();
}

const applyAvailBadges = () => {
  let result = '';

  if (currentAvail === 'MAINTENANCE') {
    result = `<span style="margin-left: 10px;" class="badge bg-warning"><i class="fa fa-wrench" aria-hidden="true"></i> Maintenance</span>`
  } else if (currentAvail === 'DISABLED') {
    result = `<span style="margin-left: 10px;" class="badge bg-danger"><i class="fa fa-times" aria-hidden="true"></i> Disabled</span>`
  }

  availBadges.html(result);
}
const setStatus = (message, isError = false) => {
  status.removeClass('text-success text-danger').addClass(isError ? 'text-danger' : 'text-success').text(message);
};

const applyControlState = () => {
  const manual = currentMode === 'MANUAL';
  const hasManualDevices = manualDevices.length > 0;
  const canCommand = manual && !hasManualDevices;
  const manualDeviceReason = manualDevices.length > 0 ? 'Device not in AUTO: ' + manualDevices.join('; ') : '';
  const commandReason = !manual ? 'Cooling tower control mode must be MANUAL' : manualDeviceReason;

  stateText.text(currentState);
  stateText.parent().removeClass(['alert-primary', 'alert-secondary', 'alert-warning', 'alert-danger']);
  if (currentState === 'OFF') {
    stateText.parent().addClass('alert-secondary');
  } else if (currentState === 'RUNNING') {
    stateText.parent().addClass('alert-primary');
  } else if (currentState === 'STARTING' || currentState === 'STOPPING') {
    stateText.parent().addClass('alert-warning');
  } else {
    stateText.parent().addClass('alert-danger');
  }

  startStopButtons.prop('disabled', !canCommand);
  startStopButtons.attr('title', '');
  startButtonWrapper.attr('title', canCommand ? '' : commandReason);
  stopButtonWrapper.attr('title', canCommand ? '' : commandReason);
  renderManualDevices();
};

const parseBody = async (response) => {
  const text = await response.text();
  if (!text) return undefined;
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

const errorMessage = (response, body) => {
  if (typeof body === 'string') return `${body} (${response.status})`;
  if (body?.error) return `${body.error} (${response.status})`;
  return `HTTP ${response.status}`;
};

const callApi = async ({ url, body, successMessage, onSuccess }) => {
  if (!equipmentId) {
    setStatus('Missing cooling tower id.', true);
    return;
  }

  status.removeClass('text-success text-danger').text('Sending command...');
  buttons.prop('disabled', true);
  mode.prop('disabled', true);
  availability.prop('disabled', true);

  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const responseBody = await parseBody(response);

    if (!response.ok) {
      setStatus(errorMessage(response, responseBody), true);
      return;
    }

    if (onSuccess) onSuccess(responseBody);
    setStatus(`${successMessage} (${response.status}).`);
  } catch (error) {
    setStatus(`Command failed: ${error.message}`, true);
  } finally {
    buttons.prop('disabled', false);
    mode.prop('disabled', false);
    availability.prop('disabled', false);
    applyControlState();
  }
};

applyControlState();
applyModeBadges();
applyModeUpdateState();
applyAvailBadges();
applyDeviceModeBadges();

mode.off('change.modeUpdateState').on('change.modeUpdateState', applyModeUpdateState);

panel.find('.cooling-tower-change-mode').off('click').on('click', () => {
  if (mode.val() == '') return;
  return callApi({
    url: `/cpms/controlStatus/package/${equipmentId}/control-mode`,
    body: { equipmentKind: 'COOLING_TOWER', controlMode: mode.val() },
    successMessage: `Cooling tower mode set to ${mode.val() === 'MANUAL' ? 'REMOTE' : 'AUTO' }`,
    onSuccess: () => {
      setLocalMode(mode.val());
      mode.val('');
      applyModeUpdateState();
    },
  })
});

panel.find('.cooling-tower-change-availability').off('click').on('click', () => {
  if (availability.val() == '') return;
  return callApi({
    url: `/cpms/controlStatus/package/${equipmentId}/availability`,
    body: { equipmentKind: 'COOLING_TOWER', availability: availability.val() },
    successMessage: `Cooling tower availability set to ${availability.val()}`,
    onSuccess: () => {
      setLocalAvail(availability.val());
      availability.val('');
    },
  })
});

panel.find('.tower-start').off('click').on('click', () => callApi({
  url: `/cpms/control/cooling-tower/${equipmentId}/command`,
  body: { command: 'START' },
  successMessage: 'Cooling tower start sequence accepted',
  onSuccess: () => { currentState = 'STARTING'; },
}));

panel.find('.tower-stop').off('click').on('click', () => callApi({
  url: `/cpms/control/cooling-tower/${equipmentId}/command`,
  body: { command: 'STOP' },
  successMessage: 'Cooling tower stop sequence accepted',
  onSuccess: () => { currentState = 'STOPPING'; },
}));

options.helpers:
context.handlebars.registerHelper('lowerCase', str => str.toLowerCase());

context.handlebars.registerHelper('autoBadge', (autoMode, remoteMode) => {
  let result = '';

  if (autoMode != null && autoMode !== 'AUTO') {
    result += `<span style="margin-left: 10px;" class="badge rounded-pill bg-danger"><i class="fa fa-user" aria-hidden="true"></i> Manual</span>`
