const stateText = panel.find('.state-text');
const speedInput = panel.find('.ctFan-speed');
const buttons = panel.find('button');
const startStopButtons = panel.find('.ctFan-start, .ctFan-stop');
const startButtonWrapper = panel.find('.ctFan-start-wrapper');
const stopButtonWrapper = panel.find('.ctFan-stop-wrapper');
const speedButtonWrapper = panel.find('.ctFan-set-speed-wrapper');
const speedControls = panel.find('.ctFan-speed, .ctFan-set-speed');
let currentMode = context.data?.remoteMode === 'AUTO' ? 'AUTO' : 'MANUAL';
let currentState = context.data?.state || 'UNKNOWN';
mode.val('');
availability.val(context.data?.availability || 'AVAILABLE');
speedInput.val(Number.isFinite(Number(context.data?.speedCmd)) ? Number(context.data.speedCmd).toFixed(1) : '');

const displayState = (state) => state;
const applyStateAlert = () => {
  stateText.text(displayState(currentState));
  stateText.parent().removeClass(['alert-primary', 'alert-secondary', 'alert-warning', 'alert-danger']);
  if (currentState === 'OFF') {
    stateText.parent().addClass('alert-secondary');
  } else if (currentState === 'RUNNING' || currentState === 'OPEN') {
    stateText.parent().addClass('alert-primary');
  } else if (currentState === 'STARTING' || currentState === 'STOPPING') {
    stateText.parent().addClass('alert-warning');
  } else {
    stateText.parent().addClass('alert-danger');
  }
};
const refreshPanel = (delayMs = 800) => {
