  setpointControls.attr('title', manual ? '' : manualReason);
  clearAlarmButton.attr('title', '');
  startButtonWrapper.attr('title', manual ? '' : manualReason);
  stopButtonWrapper.attr('title', manual ? '' : manualReason);
  setpointButtonWrapper.attr('title', manual ? '' : manualReason);
  clearAlarmButtonWrapper.attr('title', currentAlarm ? '' : 'No chiller alarm is active');
};

const parseBody = async (response) => {
  const text = await response.text();
  if (!text) return undefined;
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

const errorMessage = (response, body) => {
  if (typeof body === 'string') return `${body} (${response.status})`;
  if (body?.error) return `${body.error} (${response.status})`;
  return `HTTP ${response.status}`;
};

const callApi = async ({ url, body, successMessage, onSuccess, refreshDelays = [5500] }) => {
  if (!equipmentId) {
    setStatus('Missing chiller id.', true);
    return;
  }

  status.removeClass('text-success text-danger').text('Sending command...');
  buttons.prop('disabled', true);
  mode.prop('disabled', true);
  availability.prop('disabled', true);
  setpointInput.prop('disabled', true);

  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const responseBody = await parseBody(response);

    if (!response.ok) {
      setStatus(errorMessage(response, responseBody), true);
      return;
    }

    if (onSuccess) onSuccess(responseBody);
    setStatus(`${successMessage} (${response.status}).`);
    refreshDelays.forEach(refreshPanel);
  } catch (error) {
    setStatus(`Command failed: ${error.message}`, true);
  } finally {
    buttons.prop('disabled', false);
    mode.prop('disabled', false);
    availability.prop('disabled', false);
    setpointInput.prop('disabled', false);
    applyControlState();
  }
};

applyControlState();
applyModeBadges();
applyModeUpdateState();
applyAlarmBadges();

mode.off('change.modeUpdateState').on('change.modeUpdateState', applyModeUpdateState);

panel.find('.chr-change-mode').off('click').on('click', () => {
  if (mode.val() === '') return;
  return callApi({
    url: `/cpms/controlStatus/equipment/${equipmentId}/control-mode`,
    body: { equipmentKind: 'CHILLER', controlMode: mode.val() },
    successMessage: `Chiller mode set to ${mode.val() === 'MANUAL' ? 'REMOTE' : mode.val()}`,
    onSuccess: () => {
      setLocalMode(mode.val());
      mode.val('');
      applyModeUpdateState();
    },
  });
});

