options.afterRender:
import("https://esm.sh/bootstrap@5.0.2");

const panel = $('#plantControlPanel');
const mode = panel.find('#plantControlMode');
const scheduleToggle = panel.find('#scheduleAuthorityEnabled');
const status = panel.find('#plantControlStatus');
const buttons = panel.find('button');
const controls = {
  changeMode: panel.find('#plantChangeMode'),
  takeManualControl: panel.find('#plantTakeManualControl'),
  start: panel.find('#plantStart'),
  stop: panel.find('#plantStop'),
  scheduleUpdate: panel.find('#plantScheduleAuthorityUpdate'),
  emergencyEnable: panel.find('#plantEmergencyEnable'),
  emergencyClear: panel.find('#plantEmergencyClear'),
  reset: panel.find('#plantReset'),
  recoveryReset: panel.find('#plantRecoveryReset'),
};

const rows = context.data;
const plantData = rows[0][0]; //.find((row) => row && (row.controlMode !== undefined || row.emergency !== undefined || row.lockout !== undefined || row.state !== undefined)) || {};
window.plantData = plantData;
const scheduleData = rows[1][0];//.find((row) => row && row.key === 'schedule.enabled') || rows.find((row) => row && row.value !== undefined && row.controlMode === undefined) || {};
window.scheduleData = scheduleData;
const parseBoolean = (value, fallback = true) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') {
    const normalized = value.trim().replace(/^"|"$/g, '').toLowerCase();
    if (normalized === 'true') return true;
    if (normalized === 'false') return false;
  }
  return fallback;
};

const { controlMode, emergency = false, lockout = false, state = 'UNAVAILABLE' } = plantData;
let currentControlMode = controlMode === 'MANUAL' ? 'MANUAL' : 'AUTO';
let currentEmergency = Boolean(emergency);
let currentLockout = Boolean(lockout);
let currentPlantState = state || 'UNAVAILABLE';
let currentScheduleEnabled = parseBoolean(scheduleData.value, true);

mode.val(currentControlMode);
scheduleToggle.prop('checked', currentScheduleEnabled);

const setStatus = (message, isError = false) => {
  status.removeClass('text-success text-danger').addClass(isError ? 'text-danger' : 'text-success').text(message);
};

const setDisabled = (element, disabled, reason = '') => {
  element.prop('disabled', disabled);
  element.attr('title', disabled && reason ? reason : '');
};

const blockReason = () => {
  if (currentEmergency) return 'Plant is in emergency';
  if (currentLockout) return 'Plant is in lockout';
  return '';
};

const applyControlState = () => {
  const blocked = currentEmergency || currentLockout;
  const startAllowed = currentPlantState === 'OFF';
  const stopAllowed = currentPlantState === 'STARTING' || currentPlantState === 'RUNNING';
  const blockedReason = blockReason();
  const scheduleReason = 'Schedule authority is enabled';
  const startStateReason = 'Plant must be OFF before start is allowed';
  const stopStateReason = 'Plant must be STARTING or RUNNING before stop is allowed';
  const startReason = blocked ? blockedReason : currentScheduleEnabled ? scheduleReason : startStateReason;
  const stopReason = blocked ? blockedReason : currentScheduleEnabled ? scheduleReason : stopStateReason;
  const takeoverAllowed = !blocked && mode.val() === 'MANUAL';
  const takeoverReason = blocked ? blockedReason : 'Select Manual mode before taking manual control';

  setDisabled(mode, blocked, blockedReason);
  setDisabled(controls.changeMode, blocked, blockedReason);
  setDisabled(controls.takeManualControl, !takeoverAllowed, takeoverReason);
  setDisabled(controls.start, blocked || currentScheduleEnabled || !startAllowed, startReason);
  setDisabled(controls.stop, blocked || currentScheduleEnabled || !stopAllowed, stopReason);
  setDisabled(scheduleToggle, false);
  setDisabled(controls.scheduleUpdate, false);
  setDisabled(controls.emergencyEnable, currentEmergency, 'Plant emergency is already enabled');
  setDisabled(controls.emergencyClear, !currentEmergency, 'Plant emergency is not active');
  setDisabled(controls.reset, !currentEmergency && !currentLockout, 'Plant is not in emergency or lockout');
  setDisabled(controls.recoveryReset, blocked, blockedReason);
};

const parseBody = async (response) => {
  const text = await response.text();
  if (!text) return undefined;
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

const errorMessage = (response, body) => {
  if (response.status === 409 && body?.activeChillerAlarms) {
    const active = body.activeChillerAlarms
      .map((alarm) => alarm.chillerId + ': alarm=' + alarm.alarm + ', trip=' + alarm.trip)
      .join('; ');
    return (body.error || 'Recovery reset rejected') + ' (' + response.status + '). ' + active;
  }

  if (typeof body === 'string') return body + ' (' + response.status + ')';
  if (body?.error) return body.error + ' (' + response.status + ')';
  return 'HTTP ' + response.status;
};

const callApi = async ({ url, method = 'POST', body, successMessage, confirmMessage, onSuccess }) => {
  if (confirmMessage && !window.confirm(confirmMessage)) return;

  status.removeClass('text-success text-danger').text('Sending command...');
  buttons.prop('disabled', true);
  mode.prop('disabled', true);
  scheduleToggle.prop('disabled', true);

  try {
    const options = { method };
    if (body !== undefined) {
      options.headers = { 'Content-Type': 'application/json' };
      options.body = JSON.stringify(body);
    }

    const response = await fetch(url, options);
    const responseBody = await parseBody(response);

    if (!response.ok) {
      setStatus(errorMessage(response, responseBody), true);
      return;
    }

    if (onSuccess) onSuccess(responseBody);
    setStatus(successMessage + ' (' + response.status + ').');
  } catch (error) {
    setStatus('Command failed: ' + error.message, true);
  } finally {
    buttons.prop('disabled', false);
    mode.prop('disabled', false);
    scheduleToggle.prop('disabled', false);
    applyControlState();
  }
};

applyControlState();
mode.off('change.plantControlState').on('change.plantControlState', applyControlState);

panel.find('#plantChangeMode').off('click').on('click', () => callApi({
  url: '/cpms/controlStatus/plant/control-mode',
  body: { controlMode: mode.val() },
  successMessage: 'Plant control mode set to ' + mode.val(),
  onSuccess: () => { currentControlMode = mode.val(); },
}));

panel.find('#plantTakeManualControl').off('click').on('click', () => callApi({
  url: '/cpms/controlStatus/plant/control-mode',
  body: { controlMode: 'MANUAL', clearActiveSequences: true },
  successMessage: 'Manual takeover accepted. Active sequences cleared',
  confirmMessage: 'Take manual control and cancel active chiller/cooling tower sequences?',
  onSuccess: () => {
    currentControlMode = 'MANUAL';
    mode.val('MANUAL');
  },
}));

panel.find('#plantScheduleAuthorityUpdate').off('click').on('click', () => {
  const enabled = scheduleToggle.is(':checked');
  callApi({
    url: '/cpms/control/schedule-enabled',
    body: { value: enabled },
    successMessage: enabled ? 'Plant schedule authority enabled' : 'Plant schedule authority disabled',
    confirmMessage: enabled ? undefined : 'Disable schedule authority and use manual plant start/stop request?',
    onSuccess: () => { currentScheduleEnabled = enabled; },
  });
});

panel.find('#plantStart').off('click').on('click', () => callApi({
  url: '/cpms/control/requestOn',
  body: { value: true },
  successMessage: 'Plant start request accepted',
  onSuccess: () => { currentPlantState = 'STARTING'; },
}));

panel.find('#plantStop').off('click').on('click', () => callApi({
  url: '/cpms/control/requestOn',
  body: { value: false },
  successMessage: 'Plant stop request accepted',
  confirmMessage: 'Stop chiller plant?',
  onSuccess: () => { currentPlantState = 'STOPPING'; },
}));

panel.find('#plantEmergencyEnable').off('click').on('click', () => callApi({
  url: '/cpms/control/emergency',
  body: { value: true },
  successMessage: 'Plant emergency enabled',
  confirmMessage: 'Enable plant emergency stop?',
  onSuccess: () => { currentEmergency = true; },
}));

panel.find('#plantEmergencyClear').off('click').on('click', () => callApi({
  url: '/cpms/control/emergency',
  body: { value: false },
  successMessage: 'Plant emergency cleared',
  confirmMessage: 'Clear plant emergency?',
  onSuccess: () => { currentEmergency = false; },
}));

panel.find('#plantReset').off('click').on('click', () => callApi({
  url: '/cpms/control/reset',
  method: 'GET',
  successMessage: 'Emergency and lockout reset accepted',
  confirmMessage: 'Reset plant emergency and lockout?',
  onSuccess: () => {
    currentEmergency = false;
    currentLockout = false;
  },
}));

panel.find('#plantRecoveryReset').off('click').on('click', () => callApi({
  url: '/cpms/control/recovery-reset',
  body: {},
  successMessage: 'Plant recovery reset accepted',
  confirmMessage: 'Reset plant recovery state?',
}));

