options.afterRender:
const equipmentId = context.data?.chillerId;
const panel = $(`.chiller-package-control[data-equipment-id="${equipmentId}"]`);
const mode = panel.find('.chiller-package-mode');
const modeUpdateButton = panel.find('.chiller-package-change-mode');
const modeBadges = panel.find('.mode-badges');
const deviceModeBadges = panel.find('.device-mode-badges');
const availBadges = panel.find('.avail-badges');
const availability = panel.find('.chiller-package-availability');
const chwp = panel.find('.chiller-package-chwp-select');
const chwpButton = panel.find('.chiller-package-change-chwp');
const cwp = panel.find('.chiller-package-cwp-select');
const cwpButton = panel.find('.chiller-package-change-cwp');
const status = panel.find('.chiller-package-status');
const stateText = panel.find('.state-text');
const manualDevicesPanel = panel.find('.chiller-manual-devices');
const stateLabel = panel.find('h6 span').first();
const buttons = panel.find('button');
const startButton = panel.find('.chiller-start');
const stopButton = panel.find('.chiller-stop');
const startButtonWrapper = panel.find('.chiller-start-wrapper');
const stopButtonWrapper = panel.find('.chiller-stop-wrapper');
const startStopButtons = panel.find('.chiller-start, .chiller-stop');
let currentMode = context.data?.remoteMode === 'AUTO' ? 'AUTO' : 'MANUAL';
let currentState = context.data?.state || 'UNKNOWN';
let currentAvail = context.data?.availability || 'AVAILABLE';

chwp.val(context.data?.chwPump?.deviceId || '');
cwp.val(context.data?.cwPump?.deviceId || '');

const equipmentName = (fallback, device) => device?.deviceId || device?.id || fallback;
const modeIssue = (device) => {
  const issues = [];
  if (device?.autoMode && device.autoMode !== 'AUTO') issues.push('Manual');
  if (device?.remoteMode && device.remoteMode !== 'AUTO') issues.push('Remote');
  return issues;
};
const collectManualDevices = () => {
  const manualDevices = [];
  const addDevice = (label, device) => {
    const issues = modeIssue(device);
    if (issues.length > 0) manualDevices.push((label + ' ' + equipmentName('', device) + ' (' + issues.join(', ') + ')').trim());
  };

  addDevice('Chiller', context.data?.chiller);
  addDevice('CHWP', context.data?.chwPump);
  addDevice('CWP', context.data?.cwPump);
  return manualDevices;
};
let manualDevices = collectManualDevices();

const renderManualDevices = () => {
  if (manualDevices.length === 0) {
    manualDevicesPanel.empty();
    return;
  }

  manualDevicesPanel.html('<span class="chiller-manual-devices-title">Manual/remote devices:</span> ' + manualDevices.join(', '));
};

const setStatus = (message, isError = false) => {
  status.removeClass('text-success text-danger').addClass(isError ? 'text-danger' : 'text-success').text(message);
};

const refreshPanel = (delayMs = 800) => {
  setTimeout(() => {
    // context?.grafana?.locationService?.partial?.({ refresh: Date.now() }, true);
    context.grafana.refresh();
  }, delayMs);
};

const applyModeUpdateState = () => {
  modeUpdateButton.prop('disabled', mode.val() === '');
};
const setLocalMode = (mode) => {
  currentMode = mode;
  applyModeBadges();
}

const applyModeBadges = () => {
  let result = '';

  if (currentMode !== 'AUTO') {
    result = `<span style="margin-left: 10px;" class="badge rounded-pill bg-orange"><i class="fa fa-user" aria-hidden="true"></i> Remote</span>`
  } else {
    result = `<span style="margin-left: 10px;" class="badge rounded-pill bg-success"><i class="fa fa-leaf" aria-hidden="true"></i> Auto</span>`
  }

  modeBadges.html(result);
}

const applyDeviceModeBadges = () => {
  let result = '';

  if (manualDevices.length > 0) {
    result = `<span style="margin-left: 10px;" class="badge rounded-pill bg-warning" title="At least one device is in MANUAL or REMOTE mode"><i class="fa fa-child" aria-hidden="true"></i> Device</span>`
  }
  deviceModeBadges.html(result);
}


const setLocalAvail = (avail) => {
  currentAvail = avail;
  applyAvailBadges();
}

const applyAvailBadges = () => {
  let result = '';

  if (currentAvail === 'MAINTENANCE') {
    result = `<span style="margin-left: 10px;" class="badge bg-warning"><i class="fa fa-wrench" aria-hidden="true"></i> Maintenance</span>`
  } else if (currentAvail === 'DISABLED') {
    result = `<span style="margin-left: 10px;" class="badge bg-danger"><i class="fa fa-times" aria-hidden="true"></i> Disabled</span>`
  }

  availBadges.html(result);
}

const setLocalState = (state) => {
  currentState = state;
  stateLabel.removeClass().addClass(String(state).toLowerCase()).text(state);
  applyControlState();
};

const applyControlState = () => {
  const manual = currentMode === 'MANUAL';
  const hasManualDevices = manualDevices.length > 0;
  const canStart = manual && !hasManualDevices && currentState === 'OFF';
  const canStop = manual && !hasManualDevices && (currentState === 'STARTING' || currentState === 'RUNNING');
  const canAssignPump = currentState === 'OFF' || currentState === 'UNAVAILABLE';
  const manualDeviceReason = manualDevices.length > 0 ? 'Device not in AUTO: ' + manualDevices.join('; ') : '';
  const startReason = !manual
    ? 'Chiller package control mode must be MANUAL'
    : hasManualDevices
      ? manualDeviceReason
      : 'Chiller package must be OFF before start is allowed';
  const stopReason = !manual
    ? 'Chiller package control mode must be MANUAL'
    : hasManualDevices
      ? manualDeviceReason
      : 'Chiller package must be STARTING or RUNNING before stop is allowed';

  stateText.text(currentState);
  // set class
  stateText.parent().removeClass(['alert-primary', 'alert-secondary', 'alert-warning', 'alert-danger']);
  if (currentState === 'OFF') {
    stateText.parent().addClass('alert-secondary');
  } else if (currentState === 'RUNNING') {
    stateText.parent().addClass('alert-primary');
  } else if (currentState === 'STARTING' || currentState === 'STOPPING') {
    stateText.parent().addClass('alert-warning');
  } else {
    stateText.parent().addClass('alert-danger');
  }

  startButton.prop('disabled', !canStart);
  startButtonWrapper.attr('title', canStart ? '' : startReason);
  stopButton.prop('disabled', !canStop);
  stopButtonWrapper.attr('title', canStop ? '' : stopReason);
  chwp.prop('disabled', !canAssignPump);
  chwpButton.prop('disabled', !canAssignPump);
  chwpButton.attr('title', canAssignPump ? '' : 'CHWP assignment can only be changed when the chiller package is not operating');
  cwp.prop('disabled', !canAssignPump);
  cwpButton.prop('disabled', !canAssignPump);
  cwpButton.attr('title', canAssignPump ? '' : 'CWP assignment can only be changed when the chiller package is not operating');
  renderManualDevices();
};

const parseBody = async (response) => {
  const text = await response.text();
  if (!text) return undefined;
  try {
    return JSON.parse(text);
  } catch {
    return text;
  }
};

const errorMessage = (response, body) => {
  if (typeof body === 'string') return `${body} (${response.status})`;
  if (body?.error) return `${body.error} (${response.status})`;
  return `HTTP ${response.status}`;
};

const callApi = async ({ url, body, successMessage, onSuccess, refreshDelays = [5500] }) => {
  if (!equipmentId) {
    setStatus('Missing chiller package id.', true);
    return;
  }

  status.removeClass('text-success text-danger').text('Sending command...');
  buttons.prop('disabled', true);
  mode.prop('disabled', true);
  availability.prop('disabled', true);
  chwp.prop('disabled', true);
  cwp.prop('disabled', true);

  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });
    const responseBody = await parseBody(response);

    if (!response.ok) {
      setStatus(errorMessage(response, responseBody), true);
      return;
    }

    if (onSuccess) onSuccess(responseBody);
    setStatus(`${successMessage} (${response.status}).`);
    refreshDelays.forEach(refreshPanel);
  } catch (error) {
    setStatus(`Command failed: ${error.message}`, true);
  } finally {
    buttons.prop('disabled', false);
    mode.prop('disabled', false);
    availability.prop('disabled', false);
    chwp.prop('disabled', false);
    cwp.prop('disabled', false);
    applyControlState();
  }
};

applyControlState();
applyModeBadges();
applyModeUpdateState();
applyAvailBadges();
applyDeviceModeBadges();

mode.off('change.modeUpdateState').on('change.modeUpdateState', applyModeUpdateState);

panel.find('.chiller-package-change-mode').off('click').on('click', () => {
  if (mode.val() == '') return;
  return callApi({
    url: `/cpms/controlStatus/package/${equipmentId}/control-mode`,
    body: { equipmentKind: 'CHILLER_PACKAGE', controlMode: mode.val() },
    successMessage: `Chiller package mode set to ${mode.val() === 'MANUAL' ? 'REMOTE' : mode.val() }`,
    onSuccess: () => {
      setLocalMode(mode.val());
      mode.val('');
      applyModeUpdateState();
    },
  })
});

panel.find('.chiller-package-change-availability').off('click').on('click', () => {
  if (availability.val() === '') return;
  return callApi({
    url: `/cpms/controlStatus/package/${equipmentId}/availability`,
    body: { equipmentKind: 'CHILLER_PACKAGE', availability: availability.val() },
    successMessage: `Chiller package availability set to ${availability.val()}`,
    onSuccess: () => {
      setLocalAvail(availability.val());
      availability.val('');
    }
  })
});

panel.find('.chiller-package-change-chwp').off('click').on('click', () => callApi({
