options.afterRender:
import("https://esm.sh/bootstrap@5.0.2");

const panel = $('#bypassValvePanel');
const input = panel.find('#bypassValveSvInput');
const button = panel.find('#bypassValveSetSv');
const status = panel.find('#bypassValveCommandStatus');

button.off('click').on('click', async () => {
  const sv = Number(input.val());

  status.removeClass('text-success text-danger').text('');

  if (!Number.isFinite(sv)) {
    status.addClass('text-danger').text('Invalid SV. Enter a finite number.');
    input.addClass('is-invalid');
    return;
  }

  input.removeClass('is-invalid');
  button.prop('disabled', true).text('Setting...');

  try {
    const response = await fetch('/cpms/control/bypassValve/sv', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sv }),
    });
    const responseText = await response.text();

    if (!response.ok) {
      throw new Error(responseText || `HTTP ${response.status}`);
    }

    status.addClass('text-success').text(`SV command accepted (${response.status}).`);
  } catch (error) {
    status.addClass('text-danger').text(`SV command failed: ${error.message}`);
  } finally {
    button.prop('disabled', false).text('Set SV');
  }
});

